const express = require('express');
const winston = require('winston');
const morgan = require('morgan');

const app = express();

// Set up request logging with Winston and Morgan
app.use(morgan('combined', { stream: winston.stream }));

// Set up user input handling for log messages
app.post('/log', (req, res) => {
  const { username, ipAddress, customHeader } = req.body;
  const message = `${username} (${ipAddress}) - ${customHeader}`;
  winston.info(message);
  res.sendStatus(201);
});

